export const faqs: FAQItem[] = [
  // === TITLE & OWNERSHIP (basics) ===
  { q: "What is title?", a: "Title is your legal right to own, use, and dispose of your property. It establishes your ownership interest and any limitations on that ownership — such as easements, liens, or deed restrictions. When you buy a home, you receive title through a deed that's recorded with your county.", cat: "basics" },
  { q: "What is a title search?", a: "A title search is a thorough examination of public records — deeds, mortgages, court records, tax records, and other documents — going back decades to verify a clear chain of ownership. Title professionals trace every transfer of ownership, looking for outstanding liens, judgments, easements, or other issues that could affect your rights. According to ALTA, approximately 1 in 3 title searches reveals an issue that must be resolved before closing.", cat: "basics" },
  { q: "What is a deed and how is it different from a title?", a: "A deed is the physical legal document that transfers property ownership from one party to another — it's what gets signed at closing and recorded with the county. Title is the concept of ownership itself — your legal right to the property. Think of the deed as the vehicle that delivers title. Types include: warranty deed (strongest — seller guarantees clear title), special warranty deed (seller warrants only during their ownership), and quitclaim deed (no warranties — transfers whatever interest the grantor has).", cat: "basics" },
  { q: "What is a chain of title?", a: "The chain of title is the complete history of ownership transfers for a property, from the original land patent (government grant) through every subsequent owner to the present day. Each link in the chain is a recorded deed or other transfer document. Any break, gap, or irregularity in the chain can create a title defect that clouds your ownership. This is one of the primary things the title search examines.", cat: "basics" },
  { q: "What is a lien?", a: "A lien is a legal claim against a property that serves as security for a debt. Common types include: mortgage liens (from your home loan), property tax liens (unpaid taxes), mechanic's liens (unpaid contractors), HOA liens (unpaid association dues), and judgment liens (court-ordered debts). Liens must typically be paid off or released before a property can be sold with clear title.", cat: "basics" },
  { q: "What is an easement?", a: "An easement is the legal right for someone other than the property owner to use a portion of the property for a specific purpose. Common examples include utility easements (allowing power, water, or sewer companies to access their infrastructure), access easements (allowing a neighbor to use your driveway), and drainage easements. Easements 'run with the land' — they transfer to new owners automatically and typically cannot be removed.", cat: "basics" },
  { q: "What is an encumbrance?", a: "An encumbrance is any claim, lien, charge, or liability attached to a property that may affect its value or limit its use — but doesn't prevent the transfer of ownership. Encumbrances include mortgages, liens, easements, deed restrictions, and encroachments. They're identified during the title search and listed as exceptions on your title commitment.", cat: "basics" },
  { q: "What does ALTA do?", a: "The American Land Title Association (ALTA) is the national trade organization for the title insurance industry, representing 6,000+ member companies across all 50 states. Founded in 1907, ALTA develops industry best practices, advocates before Congress and federal agencies, provides professional education, and helps consumers understand title insurance. ALTA does NOT issue policies directly — that's done by member title companies and underwriters.", cat: "basics" },
  { q: "What is a cloud on title?", a: "A cloud on title is any irregularity, possible claim, or encumbrance that could impair the owner's title or make it unmarketable. Examples include an unreleased mortgage from a previous owner, a missing heir who might claim ownership, a forged deed in the chain of title, or an improperly recorded document. Clouds must be resolved ('cured') before title insurance can be issued. This curative work is one of the most valuable services title professionals provide.", cat: "basics" },
  { q: "What is adverse possession?", a: "Adverse possession is a legal doctrine that allows someone who occupies land they don't own to eventually claim legal ownership — if they meet specific requirements for a period set by state law (typically 5-20 years). The possession must generally be open, notorious, continuous, exclusive, and hostile (without the owner's permission). Title insurance protects against claims of adverse possession.", cat: "basics" },

  // === TITLE INSURANCE (insurance) ===
  { q: "What is title insurance?", a: "Title insurance is a policy that protects your investment and property rights against losses from defects in the title that existed before you purchased the property — even if those defects weren't discovered during the title search. Unlike other insurance that covers future events (fire, theft), title insurance protects against past events that haven't been discovered yet. It's a one-time premium paid at closing for lifetime coverage.", cat: "insurance" },
  { q: "Why should I purchase owner's title insurance?", a: "Owner's title insurance provides permanent protection for your property investment against future legal claims regarding ownership. For a one-time fee at closing (typically 0.5-1% of the purchase price), you and your heirs receive coverage for as long as you own the home. The policy covers legal defense costs (which can exceed $50,000 even for baseless claims) and pays covered losses up to your policy amount. Without it, you'd personally bear these costs.", cat: "insurance" },
  { q: "What's the difference between an owner's policy and a lender's policy?", a: "A lender's policy protects only the mortgage lender's investment — it does NOT protect you as the homeowner. It covers the declining loan balance, not your equity. An owner's policy protects YOUR equity and ownership rights for as long as you own the property. Most lenders require a lender's policy as a mortgage condition, but the owner's policy is optional (and strongly recommended). Purchasing both simultaneously typically qualifies for a significant discount.", cat: "insurance" },
  { q: "What does owner's title insurance cover?", a: "The ALTA Owner's Policy covers specific risks including: someone else claiming ownership of your property; forged or fraudulently executed documents in the chain of title; documents signed by minors or incapacitated persons; improperly recorded documents; unknown liens or encumbrances; restrictions that were violated by a previous owner; lack of legal access to the property; and unmarketable title that prevents you from selling. The policy also covers your legal defense costs for covered claims.", cat: "insurance" },
  { q: "What does owner's title insurance NOT cover?", a: "Title insurance does not cover: defects, liens, or encumbrances created by you after the policy date; government regulations (zoning, building codes) unless they cause a loss of title; defects that you agreed to or knew about; environmental contamination; matters that would be revealed by a physical survey (unless survey coverage is added); and items specifically listed as exceptions in Schedule B of your policy. Always review Schedule B carefully.", cat: "insurance" },
  { q: "How much does title insurance cost?", a: "Owner's title insurance typically costs 0.5% to 1% of the purchase price — a one-time fee for lifetime coverage. For a $350,000 home, that's approximately $1,750 to $3,500. Rates are regulated by each state's department of insurance. In some states (like Texas), rates are set by the state and are uniform. In others, rates vary by company — which is why RESPA gives you the right to shop. Ask about simultaneous issue discounts when buying both owner's and lender's policies.", cat: "insurance" },
  { q: "How long does title insurance coverage last?", a: "Your owner's title insurance policy lasts for as long as you or your heirs own the property. There are no annual premiums, no renewals, and no expiration date — you pay once at closing and you're covered for life. If you leave the property to your heirs, they inherit the coverage. The only way coverage ends is when you sell the property or transfer ownership.", cat: "insurance" },
  { q: "Can I choose my own title company?", a: "Yes. Under the federal Real Estate Settlement Procedures Act (RESPA), you have the legal right to choose your own title insurance company. Your lender or real estate agent may recommend a provider, but you are NOT obligated to use them, and they cannot require you to use a specific company. Shopping around can save hundreds of dollars and help you find a company you trust. Look for ALTA members who follow Best Practices.", cat: "insurance" },
  { q: "How do I file a title insurance claim?", a: "Contact your title insurance company promptly when you discover any concern. Common triggers: someone claims ownership or an interest in your property, a lien appears that wasn't disclosed at closing, a boundary dispute arises, you discover a restrictive easement, or a buyer's title search reveals a defect when you try to sell. Provide: your property address, policy number (if available), description of the issue, and supporting documents. Your insurer investigates, provides legal defense if needed, and pays covered losses.", cat: "insurance" },
  { q: "What is a title commitment?", a: "A title commitment (also called a preliminary title report) is the document your title company issues after completing the title search. It states the conditions under which the company is willing to insure your title. Schedule A shows the policy details (amount, property description, how title is vested). Schedule B lists exceptions — known issues NOT covered by the policy (easements, deed restrictions, etc.). Review Schedule B with your agent or attorney — some exceptions can be removed through curative work.", cat: "insurance" },
  { q: "What is an endorsement?", a: "A title insurance endorsement is an addition or modification to your standard policy that expands or changes coverage. Common endorsements include: survey coverage (covers boundary disputes), zoning compliance, access rights, condominium coverage, and adjustable rate mortgage protection. Endorsements are available for an additional fee and must be requested. Ask your title company which endorsements are available and recommended for your property type and location.", cat: "insurance" },

  // === COSTS & FEES (costs) ===
  { q: "What are closing costs?", a: "Closing costs are the fees and expenses beyond the purchase price that you pay to complete your home purchase. They typically range from 2% to 5% of the home price. For a $350,000 home, expect $7,000-$17,500. Major categories: loan origination (0.5-1%), appraisal ($300-600), title search ($200-400), title insurance (0.5-1% owner's policy), settlement fee ($500-2,000), recording fees ($50-250), homeowner's insurance (first year), and prepaid property taxes.", cat: "costs" },
  { q: "Can I negotiate closing costs?", a: "Yes, many closing costs are negotiable. Strategies include: comparing Loan Estimates from multiple lenders (required within 3 business days of application under CFPB rules); negotiating seller concessions (asking the seller to pay a portion — capped at 3-9% depending on loan type); shopping for title insurance (your right under RESPA); asking about lender credits (higher rate in exchange for lower fees); closing near month-end (reduces prepaid interest); and checking for first-time buyer programs in your state.", cat: "costs" },
  { q: "What is PMI and how can I avoid it?", a: "Private Mortgage Insurance is required by most lenders when your down payment is less than 20%. PMI protects the lender (not you) if you default. It typically costs 0.5-1.5% of the loan annually, added to your monthly payment. Avoid it by: putting 20%+ down, choosing a VA loan (no PMI ever), or using a piggyback loan. PMI can be removed: by request at 20% equity, automatically at 22% equity under the Homeowners Protection Act, or by refinancing once you have sufficient equity.", cat: "costs" },
  { q: "What is an escrow account?", a: "Escrow serves two purposes. During the transaction, an escrow account holds your earnest money safely with a neutral third party (usually the title company). After closing, your lender may set up a mortgage escrow account that collects a portion of your property taxes and homeowner's insurance with each monthly payment, then pays those bills when due. This ensures taxes and insurance stay current. Your initial escrow deposit at closing typically covers 2-6 months of taxes and insurance.", cat: "costs" },
  { q: "What is earnest money and do I get it back?", a: "Earnest money (1-3% of purchase price) is a deposit showing the seller you're serious. It's held in escrow by the title company. If the transaction closes, it's applied to your down payment/closing costs. If you back out for a reason covered by your contingencies (failed inspection, financing falls through, low appraisal), you typically get it back. If you back out for an uncovered reason, you may forfeit it to the seller. Know your contingency deadlines.", cat: "costs" },
  { q: "What is RESPA?", a: "The Real Estate Settlement Procedures Act is federal law protecting consumers during closing. Key protections: lenders must provide a Loan Estimate within 3 business days of application; you can choose your own title/settlement services; kickbacks between providers are prohibited; lenders can't require you to use a specific title company; you must receive a Closing Disclosure 3 days before closing; and your lender must provide an annual escrow analysis statement. Enforced by the CFPB. Source: CFPB", cat: "costs" },
  { q: "Who pays for what at closing?", a: "It varies by state and is often negotiable. Buyers typically pay: loan origination, appraisal, home inspection, lender's title insurance, homeowner's insurance, prepaid taxes/interest, and PMI. Sellers typically pay: real estate commissions (5-6%), owner's title insurance (in some states), transfer taxes, and repair credits. Your purchase agreement specifies who pays each fee. In some markets, sellers offer to pay buyer closing costs as an incentive.", cat: "costs" },
  { q: "What is a simultaneous issue discount?", a: "When you purchase both an owner's and lender's title insurance policy from the same company at the same time, many companies offer a reduced rate on the second policy. This can save $200-$500 or more. The discount is available because much of the work (title search, examination) is the same for both policies. Always ask about this discount — not all companies volunteer it.", cat: "costs" },
  { q: "What are prepaid costs?", a: "Prepaids are costs you pay at closing that cover future expenses, not closing-related fees. They include: prepaid interest (from closing date to end of month), first year's homeowner's insurance premium, initial property tax escrow deposit (typically 2-6 months), and initial insurance escrow deposit. Prepaids can add $3,000-$8,000+ to your cash needed at closing depending on when in the month you close and your tax/insurance amounts.", cat: "costs" },

  // === CLOSING PROCESS (closing) ===
  { q: "What happens at closing?", a: "Closing (settlement) is the final step where ownership transfers. You'll sign 50-100+ pages including: Closing Disclosure, promissory note (promise to repay), deed of trust (security for the loan), deed (ownership transfer), and various affidavits. The closing agent explains each document. You provide certified funds or wire confirmation. After signing, funds are disbursed, the deed is recorded with the county, and you receive the keys. Closings typically take 30-90 minutes.", cat: "closing" },
  { q: "What is the Closing Disclosure?", a: "A 5-page standardized form detailing the final terms of your mortgage and every cost you'll pay. Under the CFPB's TRID rule, your lender must deliver it at least 3 business days before closing. It shows: loan terms, projected payments, closing costs itemized, cash needed at closing, and a comparison to your Loan Estimate. If certain items change (APR increases >1/8%, prepayment penalty added, loan product changes), a new 3-day waiting period starts. Source: CFPB", cat: "closing" },
  { q: "What is the Loan Estimate?", a: "A 3-page standardized form your lender must provide within 3 business days of your mortgage application. It shows: estimated interest rate, monthly payment, closing costs, and key loan features. Get Loan Estimates from at least 3 lenders and compare APRs (not just rates) — the APR includes fees and gives the true cost. Federal law limits how much fees can increase between the Loan Estimate and Closing Disclosure. Source: CFPB", cat: "closing" },
  { q: "Can I close remotely?", a: "Four methods exist: in-person (traditional, at the settlement office), mail-away/mobile notary (documents sent to you, notary comes to your location), hybrid (most docs signed digitally, brief office visit for key papers), and Remote Online Notarization/RON (fully digital via live video). The majority of U.S. states now have RON legislation, but availability depends on your county recorder and lender. Ask your title company early. Source: ALTA", cat: "closing" },
  { q: "What is a final walk-through?", a: "The final walk-through is your last inspection of the property before closing — typically done the morning of or day before closing. You're verifying: the property is in the agreed-upon condition, all negotiated repairs were completed, no new damage occurred, all fixtures and appliances that were included in the sale are still there, and the seller has fully vacated. If you find issues, raise them BEFORE signing at closing — it's much harder to get remedies afterward.", cat: "closing" },
  { q: "What should I NOT do during the closing process?", a: "Once under contract, avoid: opening new credit cards, making large purchases on credit, changing jobs, making large unexplained cash deposits, co-signing on anyone else's loan, or closing existing credit accounts. Your lender pulls credit again before closing — any changes can delay or kill your loan approval. Even a small new debt can push your DTI past the threshold. Wait until after closing and funding to make changes.", cat: "closing" },
  { q: "How long does closing take?", a: "The closing appointment itself typically takes 30-90 minutes. However, the entire process from accepted offer to closing usually takes 30-45 days for conventional loans, 45-60 days for FHA loans, and varies for VA and USDA loans. Delays are common — common causes include appraisal issues, title defects requiring resolution, lender underwriting conditions, missing documents, and changes in the buyer's financial situation.", cat: "closing" },
  { q: "What is a dry closing vs. a wet closing?", a: "In a 'wet' closing (most common), funds are disbursed and the deed is recorded on the same day as signing. You get your keys at or shortly after the closing table. In a 'dry' closing, the documents are signed but funds are not immediately disbursed — there may be a 1-3 day delay before funds transfer and the deed records. Some states (like California, Oregon, Washington) commonly have dry closings. Ask your settlement agent which to expect.", cat: "closing" },

  // === FRAUD & SAFETY (fraud) ===
  { q: "What is wire fraud in real estate?", a: "Wire fraud occurs when criminals intercept or impersonate parties in a real estate transaction to redirect closing funds. They hack email accounts, send fake wiring instructions, and steal down payments — often hundreds of thousands of dollars. The FBI reported $275.1 million in real estate wire fraud losses in 2025, a 59% increase from the prior year. BEC (Business Email Compromise) attacks increased 1,760% since AI tools became available. Source: FBI IC3, CertifID 2026", cat: "fraud" },
  { q: "How do I verify wiring instructions are legitimate?", a: "ALWAYS call your title company using a phone number you already have on file — NEVER a number from a suspicious email. Legitimate companies: never send wire instructions solely by email, never pressure last-minute changes, use wire verification technology (CertifID, Closinglock), and will happily confirm details by phone. If anything seems unusual — stop and call. Recovery rates: ~20% within 1 hour, ~10% within 24 hours, <5% after 48 hours. Source: FBI IC3", cat: "fraud" },
  { q: "What should I do if I think I'm a victim of wire fraud?", a: "Act within MINUTES: (1) Contact your bank immediately, request a wire recall — every minute matters. (2) Call your title company using a known number. (3) File with FBI IC3 at ic3.gov. (4) File with FinCEN. (5) Contact local law enforcement. (6) Document everything — screenshot emails, save headers, note call times. The first hour is your best window for recovery. After 48 hours, recovery drops below 5%. Source: FBI IC3", cat: "fraud" },
  { q: "What is a deepfake scam in real estate?", a: "Criminals use AI to create realistic fake audio, video, or images to impersonate real estate agents, title officers, or sellers. Deepfake scams in real estate increased 40% year-over-year according to the 2026 Entrust Identity Fraud Report. They may send AI-generated voice messages with 'updated' wire instructions or conduct fake video calls impersonating your closing agent. Always verify identity through a separate, trusted channel. Source: NAR, Entrust 2026", cat: "fraud" },
  { q: "What should my title company be doing to prevent fraud?", a: "Ask if they: use wire verification technology (CertifID, Closinglock), require multi-factor authentication on all accounts, send documents through encrypted portals (not plain email), conduct regular cybersecurity training, carry cyber insurance/E&O coverage, and have a documented verbal verification process for wire instructions. Companies following ALTA Best Practices Pillar 3 (Privacy and Data Security) should have these measures in place. Source: ALTA", cat: "fraud" },

  // === MORTGAGES & LOANS (mortgage) ===
  { q: "What's the difference between pre-qualification and pre-approval?", a: "Pre-qualification is an informal estimate based on information you provide verbally — it's not verified and carries little weight with sellers. Pre-approval is a formal process where the lender verifies your income, assets, debts, and credit, then issues a conditional commitment for a specific loan amount. Pre-approval shows sellers you're a serious, qualified buyer. Get pre-approved before house hunting and obtain Loan Estimates from at least 3 lenders.", cat: "mortgage" },
  { q: "What types of mortgages are available?", a: "Four main types: Conventional (backed by Fannie Mae/Freddie Mac, 3-20% down, best rates at 740+ credit), FHA (government-insured, 3.5% down with 580+ credit, MIP for life on most loans), VA (zero down for eligible military/veterans, no monthly MI, funding fee applies), and USDA (zero down for eligible rural areas, income limits apply, lowest MI). Each has different requirements for credit score, down payment, mortgage insurance, and DTI ratio. Source: FHA.com, VA.gov, USDA.gov, Fannie Mae", cat: "mortgage" },
  { q: "What is DTI and why does it matter?", a: "Debt-to-Income ratio is your total monthly debt payments divided by your gross monthly income. Lenders use two DTI ratios: front-end (housing costs only, ideally ≤28%) and back-end (all debts, ideally ≤36%). Maximum DTI varies by loan type: Conventional (45%), FHA (43%), VA (41%), USDA (41%). A lower DTI means you're less risky to the lender and may qualify for better rates. Reduce DTI by paying down debts before applying.", cat: "mortgage" },
  { q: "Should I get a fixed or adjustable rate mortgage?", a: "Fixed-rate: same rate and payment for the entire loan term. Predictable and stable. Best if you plan to stay long-term or rates are low. Adjustable-rate (ARM): lower initial rate that adjusts periodically (usually after 5, 7, or 10 years). The rate can increase or decrease based on market indexes. Best if you plan to move or refinance before the adjustment period. ARMs have caps limiting how much the rate can change per adjustment and over the life of the loan.", cat: "mortgage" },
  { q: "What is a rate lock?", a: "A rate lock is a guarantee from your lender that your interest rate won't change for a specific period (typically 30-60 days). Once locked, your rate is protected even if market rates rise. If rates drop, you're generally stuck at your locked rate (though some lenders offer float-down options). Lock when you're comfortable with the rate and confident your closing will happen within the lock period. Lock extensions may cost extra.", cat: "mortgage" },
  { q: "What is the difference between interest rate and APR?", a: "The interest rate is the cost of borrowing the principal loan amount. The APR (Annual Percentage Rate) is the total cost of the loan including the interest rate PLUS lender fees, discount points, mortgage insurance, and other costs — expressed as a yearly rate. The APR is always equal to or higher than the interest rate. Use APR to compare loan offers from different lenders — it gives you the true cost of each option. Required on all Loan Estimates. Source: CFPB", cat: "mortgage" },

  // === INSPECTIONS (inspection) ===
  { q: "Do I really need a home inspection?", a: "Yes — it's one of the most important investments in the homebuying process. A $300-500 inspection can reveal tens of thousands in hidden problems. According to ASHI, approximately 86% of inspections find issues. The inspector examines structure, roof, plumbing, electrical, HVAC, and interior. They work for YOU, not the seller. Never waive the inspection contingency in your purchase agreement — even in competitive markets. Source: ASHI", cat: "inspection" },
  { q: "What is a home appraisal?", a: "A professional assessment of a property's fair market value, ordered by your lender to verify the home is worth the loan amount. The appraiser evaluates condition, features, location, and comparable sales. If the appraisal comes in low, you can: negotiate a lower price, increase your down payment to cover the gap, challenge the appraisal with additional comps, or walk away (if you have an appraisal contingency). Cost: $300-600, paid by the buyer. Source: Appraisal Institute", cat: "inspection" },
  { q: "Who pays for the home inspection?", a: "The buyer pays for the home inspection in the vast majority of transactions — and that's a good thing. Because you're paying the inspector, they work for you and owe their loyalty to you, not the seller. Typical cost: $300-500 for a general inspection. Specialty inspections (radon, sewer scope, mold, termite) are additional. The investment is small compared to the potential cost of undiscovered problems.", cat: "inspection" },
  { q: "What specialty inspections might I need?", a: "Based on the property and location: radon testing ($100-200, recommended everywhere — #2 cause of lung cancer), sewer scope ($150-300, strongly recommended for 20+ year homes), termite/pest ($75-150, required for some loans), mold testing ($200-600, if moisture issues found), well water ($100-500, required for private wells), septic ($250-500, required for septic systems), foundation assessment ($300-800, if significant cracks noted), and chimney ($150-500, if fireplace present). Source: ASHI, EPA, NPMA", cat: "inspection" },
  { q: "Should I get a new construction home inspected?", a: "Absolutely. Three inspections are recommended: (1) Pre-drywall inspection before walls are closed — you can see framing, plumbing, electrical, and HVAC. This is the most valuable. (2) Pre-closing inspection 1-2 weeks before final walk-through. (3) 11-month warranty inspection before the builder's 1-year warranty expires. Even new homes have defects — improper grading, HVAC errors, builder shortcuts. Cost: $300-400 per inspection. Source: InterNACHI", cat: "inspection" },

  // === DOCUMENTS (documents) ===
  { q: "What is the Closing Disclosure and when will I get it?", a: "A 5-page form with final mortgage terms and every cost. Your lender must deliver it at least 3 business days before closing (CFPB TRID rule). Compare EVERY line to your Loan Estimate. Some fees can't increase at all (zero tolerance: origination, transfer taxes), some can increase up to 10% in aggregate (title services, recording fees), and some have no limit (services you chose, prepaids). If zero-tolerance fees increased, your lender must refund the difference. Source: CFPB", cat: "documents" },
  { q: "What should I bring to closing?", a: "Required: government-issued photo ID (valid, not expired), certified/cashier's check or wire confirmation for closing costs, proof of homeowner's insurance (binder effective on/before closing date). Recommended: your Closing Disclosure (for reference), Loan Estimate (for comparison), purchase agreement, home inspection report, bank statements, and contact numbers for your lender, agent, and insurance company. Two forms of ID is safer. Arrive early.", cat: "documents" },
  { q: "What is a promissory note?", a: "Your legally binding promise to repay the mortgage loan. It specifies: the loan amount, interest rate, monthly payment amount, payment due dates, late payment penalties, and consequences of default. Unlike the deed of trust (which is recorded publicly), the promissory note is a private document between you and the lender. If you default, the note plus the deed of trust allow the lender to foreclose.", cat: "documents" },
  { q: "What is a deed of trust?", a: "Also called a security instrument or mortgage (depending on your state). It gives the lender a security interest in your property — meaning if you fail to make payments, the lender has the legal right to foreclose and sell the property to recover the loan balance. It's recorded with the county as a public record. When you pay off your mortgage, the lender records a release/reconveyance, removing their lien from your title.", cat: "documents" },

  // === YOUR RIGHTS (rights) ===
  { q: "What rights do I have as a homebuyer?", a: "Key federal rights: choose your own title company and settlement services (RESPA); receive a Loan Estimate within 3 business days of application (TRID); receive your Closing Disclosure 3 days before closing (TRID); be free from discrimination in housing (Fair Housing Act); receive a copy of your appraisal before closing; cancel certain loans within 3 days (right of rescission for refinances); and file complaints with the CFPB. State laws may provide additional protections. Source: CFPB, HUD", cat: "rights" },
  { q: "Can my lender force me to use a specific title company?", a: "No. Under RESPA, your lender cannot require you to use a specific title insurance company. They can recommend one, but you have the legal right to choose your own. If you feel pressured, remind them of your RESPA rights or file a complaint with the CFPB. Shopping around can save you money and ensure you work with a company you trust. Look for ALTA members who follow Best Practices.", cat: "rights" },
  { q: "What is the right of rescission?", a: "For mortgage refinances (not purchase loans), you have 3 business days after closing to cancel the transaction without penalty. This is your federal 'cooling off' period under the Truth in Lending Act (TILA). During this period, the lender cannot disburse funds. If you rescind, the lender must return any fees you paid within 20 days. This right does NOT apply to purchase mortgages — only refinances of your primary residence. Source: CFPB", cat: "rights" },
  { q: "What if I find errors on my Closing Disclosure?", a: "Contact your lender AND settlement agent immediately — before closing if possible. If fees increased beyond TRID tolerance limits, your lender must cure (refund) the difference. Zero-tolerance fees (origination charges, transfer taxes) cannot increase at all. 10%-tolerance fees can increase up to 10% in aggregate. If you find errors at the closing table, you can ask to delay closing to correct them. Never sign documents you believe contain errors. Source: CFPB", cat: "rights" },

  // === AFTER CLOSING (after) ===
  { q: "What happens after I close?", a: "After signing, the settlement agent disburses funds and sends your deed to the county recorder's office for recording (typically same day or next business day). Recording makes your ownership official and public. Your final title insurance policy arrives by mail in 2-8 weeks. Your first mortgage payment is usually due 30-60 days after closing. Keep all closing documents in a safe, permanent location — you'll need them for taxes, insurance claims, and when you eventually sell.", cat: "after" },
  { q: "When will I receive my title insurance policy?", a: "Your final owner's title insurance policy typically arrives by mail 2-8 weeks after closing. This is different from the title commitment (which you received before closing). The policy is your permanent proof of coverage. Store it in a safe place — you'll need it if you ever file a claim or if someone challenges your ownership. If you don't receive it within 90 days, contact your title company.", cat: "after" },
  { q: "What if I lose my title insurance policy?", a: "Contact the title company or underwriter that issued the policy. They maintain records and can provide a duplicate. If you can't remember who issued it, check your closing documents, contact the settlement agent who handled your closing, or call your state's department of insurance for help locating the insurer. Our Find My Policy page has a directory of all 50 state insurance departments with phone numbers.", cat: "after" },
  { q: "Can my mortgage be sold to another company?", a: "Yes — and it's very common. Most mortgages are sold on the secondary market after closing. Your loan terms (rate, payment, balance) cannot change when the loan is transferred, but your payment address and servicer will change. Your new servicer must notify you at least 15 days before your first payment is due to them. If both the old and new servicers fail to notify you, you have a 60-day grace period with no late fees. Source: CFPB", cat: "after" },
  { q: "How long should I keep my closing documents?", a: "Keep your closing documents for as long as you own the property — plus 3-7 years after you sell (for tax purposes). Key documents to keep permanently: deed, title insurance policy, survey, settlement statement/Closing Disclosure, and any amendments or modifications. Keep digitally and physically. You'll need them for: filing insurance claims, refinancing, resolving boundary disputes, calculating capital gains when selling, and verifying ownership.", cat: "after" },

  // === MORE MORTGAGES & LOANS ===
  { q: "How many lenders should I compare?", a: "At least 3. Under CFPB rules, each lender must provide a Loan Estimate within 3 business days of your application. Compare APRs (not just rates), origination fees, and total closing costs. Multiple mortgage credit inquiries within a 14-45 day window count as a single inquiry on your credit report, so shopping doesn't hurt your score. Even a 0.25% rate difference saves thousands over 30 years.", cat: "mortgage" },
  { q: "What is a conforming loan limit?", a: "The maximum loan amount that Fannie Mae and Freddie Mac will purchase. For 2025, the baseline conforming limit is $806,500 (higher in high-cost areas — up to $1,209,750 in the most expensive markets like San Francisco). Loans above this limit are called 'jumbo' loans and typically have stricter requirements and higher rates. FHA has its own lower limits that vary by county. Source: FHFA", cat: "mortgage" },
  { q: "What is a jumbo loan?", a: "A mortgage that exceeds the conforming loan limit ($806,500 baseline in 2025). Jumbo loans aren't backed by Fannie Mae or Freddie Mac, so lenders take on more risk and typically require: higher credit scores (700-720+), larger down payments (10-20%+), more cash reserves, lower DTI ratios, and charge higher interest rates. Jumbo loans are common in high-cost markets like New York, San Francisco, and Los Angeles.", cat: "mortgage" },
  { q: "What is a construction loan?", a: "A short-term loan that finances the building of a new home. Construction loans typically have higher interest rates, require larger down payments (20-25%), and disburse funds in stages ('draws') as construction milestones are completed. Most convert to a permanent mortgage after construction is done (construction-to-permanent loan) or require you to refinance into a traditional mortgage. Title insurance is still needed — it protects against liens filed by contractors.", cat: "mortgage" },
  { q: "Can I buy a home with student loan debt?", a: "Yes. Student loans affect your DTI ratio, but they don't disqualify you. Tips: FHA counts 1% of loan balance or actual payment (whichever is lower) for IBR/IDR plans. Conventional loans use the actual payment if documented. Pay down high-interest debts first to improve DTI. Consider income-driven repayment plans to lower monthly payments. Get pre-approved to see where you stand. Many first-time buyers successfully purchase with student debt.", cat: "mortgage" },
  { q: "What is mortgage points and should I buy them?", a: "Discount points are prepaid interest — you pay a percentage of the loan upfront to reduce your rate. One point = 1% of the loan amount and typically reduces the rate by 0.25%. Whether to buy points depends on how long you'll stay: calculate the break-even point (cost of points divided by monthly savings). If you'll own the home longer than the break-even period (usually 4-7 years), buying points saves money. If you'll move sooner, skip them.", cat: "mortgage" },
  { q: "What happens if I miss a mortgage payment?", a: "Day 1-15: Most lenders have a 15-day grace period with no penalty. Day 16-30: Late fee charged (typically 3-6% of payment). Day 30+: Reported to credit bureaus, damaging your score significantly. Day 90+: Default notice sent. Day 120+: Foreclosure process may begin (timeline varies by state — judicial foreclosure takes longer). If you're struggling, contact your servicer immediately — options include forbearance, loan modification, and repayment plans. Don't ignore it.", cat: "mortgage" },

  // === MORE CLOSING PROCESS ===
  { q: "What is a contingency?", a: "A contingency is a condition in your purchase agreement that must be met for the sale to proceed. If the contingency isn't satisfied, you can usually back out without losing your earnest money. Common contingencies: financing (loan approval), inspection (property condition), appraisal (value verification), title (clear title), and sale of current home. Each has a deadline. Missing a deadline may waive your right to exercise the contingency.", cat: "closing" },
  { q: "What is a title search and how long does it take?", a: "A title search examines public records to verify clear ownership and identify any liens, judgments, or encumbrances. It typically takes 1-2 weeks but can take longer for complex properties or if issues are discovered that need resolution. The title company traces every transfer of ownership, checks for outstanding debts, verifies legal descriptions, and identifies easements or restrictions. Issues are found in approximately 1 out of 3 searches. Source: ALTA", cat: "closing" },
  { q: "What is prorating and how does it work?", a: "Prorating divides costs between buyer and seller based on the closing date. Common prorated items: property taxes (seller pays through closing date, buyer pays the rest), HOA dues, utility bills, and prepaid insurance. For example, if property taxes are $6,000/year and you close on March 31, the seller pays for January-March ($1,500) and you're responsible for April-December. Your settlement agent handles these calculations on the Closing Disclosure.", cat: "closing" },
  { q: "What is recording and why does it matter?", a: "Recording is the act of filing your deed (and deed of trust) with the county recorder's office, making your ownership a matter of public record. Until recording happens, your ownership isn't official. Recording typically occurs the same day as closing (in 'wet' closing states) or within 1-3 days. The settlement agent handles this. Recording fees (typically $50-250) are a closing cost. After recording, you receive a confirmation and eventually the original recorded deed.", cat: "closing" },
  { q: "Can my closing be delayed?", a: "Yes — delays are common. Common causes: appraisal comes in low (requiring renegotiation), title search reveals issues needing resolution, lender underwriting requests additional documentation, inspection reveals major problems, buyer's financial situation changes (new debt, job change), document errors requiring corrections, and wire transfer issues. Build a 1-2 week buffer into your moving timeline. Rate lock extensions may cost extra if closing is delayed.", cat: "closing" },

  // === MORE COSTS ===
  { q: "What are transfer taxes?", a: "Transfer taxes (also called deed stamps, documentary stamps, or conveyance taxes) are state and/or local taxes imposed when property ownership transfers. They're calculated as a percentage of the sale price or a flat rate per dollar of value. Who pays varies by state and is often negotiable. Some states have no transfer tax (like Texas). Others are significant — New York City's combined rate can exceed 2%. These are zero-tolerance fees under TRID — they cannot increase from your Loan Estimate.", cat: "costs" },
  { q: "What is a home warranty and should I get one?", a: "A home warranty is a service contract covering repair or replacement of major home systems and appliances (HVAC, plumbing, electrical, kitchen appliances) for one year. Cost: $300-600. NOT the same as homeowner's insurance (which covers damage from disasters). Sellers sometimes provide a warranty as a selling incentive. Whether it's worth it depends on the home's age and condition. Read the contract carefully — exclusions, coverage limits, and service call fees vary.", cat: "costs" },
  { q: "How much should I budget for moving costs?", a: "For a local move (under 50 miles): $1,000-$3,000 for professional movers, or $200-$500 for a rental truck. Long-distance (over 100 miles): $3,000-$10,000+ depending on distance and volume. Additional costs: packing supplies ($100-300), storage if needed ($100-300/month), utility setup fees, address change costs, and cleaning. Budget 1-2% of your home price for immediate move-in expenses (cleaning, minor repairs, window coverings, locks).", cat: "costs" },

  // === MORE INSPECTIONS ===
  { q: "What is radon and should I test for it?", a: "Radon is a naturally occurring radioactive gas that seeps into homes from the ground. It's the #2 cause of lung cancer after smoking. The EPA recommends testing EVERY home — radon levels vary block by block, not just by region. Testing costs $100-200. If levels exceed 4 pCi/L, mitigation systems ($800-1,500) can reduce radon by up to 99%. Many buyers make testing part of their inspection contingency. Source: EPA", cat: "inspection" },
  { q: "Should I attend the home inspection?", a: "Absolutely — attending is one of the most valuable things you can do as a buyer. Walking through the home with the inspector gives you a hands-on education about the property's systems, maintenance needs, and any issues. You can ask questions in real-time, see problems firsthand, and understand the severity of findings. Most inspections take 2-4 hours. Bring a notebook and camera. Your inspector should encourage your presence.", cat: "inspection" },
  { q: "What is a 4-point inspection?", a: "A 4-point inspection is a limited inspection that examines only four major systems: roof, electrical, plumbing, and HVAC. It's typically required by insurance companies (not lenders) for older homes — usually 20-30+ years old — before they'll issue a homeowner's insurance policy. It's NOT a substitute for a full home inspection. Cost: $100-200. The insurance company wants to assess the risk of these four systems failing.", cat: "inspection" },

  // === MORE RIGHTS ===
  { q: "What is the Fair Housing Act?", a: "Federal law prohibiting discrimination in housing based on race, color, national origin, religion, sex, familial status, and disability. It applies to selling, renting, financing, and advertising housing. If you believe you've experienced discrimination during the homebuying process — from a lender, real estate agent, seller, or anyone else — you can file a complaint with HUD (hud.gov) or call 1-800-669-9777. Many states add additional protected classes. Source: HUD", cat: "rights" },
  { q: "What if the seller doesn't disclose a known defect?", a: "In most states, sellers are required to disclose known material defects. If a seller knowingly conceals a defect and you discover it after closing, you may have legal recourse — depending on your state's disclosure laws. Title insurance may cover certain undisclosed issues (like liens or encumbrances). For physical defects (foundation, mold, water damage), you may need to pursue the seller through the courts. This is why a thorough inspection before closing is critical.", cat: "rights" },
  { q: "Can I back out of a home purchase?", a: "It depends on your contingencies. With an inspection contingency, you can back out if the inspection reveals significant issues. With a financing contingency, you can exit if your loan falls through. With an appraisal contingency, you can walk if the home appraises below the purchase price. Without these contingencies, backing out typically means forfeiting your earnest money. After all contingencies expire, you're generally obligated to close or face potential legal action from the seller.", cat: "rights" },

  // === MORE AFTER CLOSING ===
  { q: "When is my first mortgage payment due?", a: "Your first payment is typically due on the first day of the second month after closing. For example, if you close on March 15, your first payment is usually due May 1. You pay prepaid interest at closing to cover March 15-31, then skip April entirely, and your regular payments begin May 1. This is normal — you're not 'skipping' a payment. Set up autopay immediately to avoid forgetting.", cat: "after" },
  { q: "Should I refinance?", a: "Consider refinancing when: rates drop 0.5-1% below your current rate, your credit score has significantly improved, you want to switch from adjustable to fixed rate, you want to remove PMI (if your home value increased enough), or you need to access equity through a cash-out refinance. Calculate the break-even point: total refinance costs divided by monthly savings. If you'll own the home longer than the break-even period, refinancing makes sense. New title insurance is typically needed.", cat: "after" },
  { q: "What is a homestead exemption?", a: "A homestead exemption reduces the taxable value of your primary residence for property tax purposes. Rules vary by state — some offer a fixed dollar reduction (like $50,000 off assessed value), others a percentage reduction. You usually must apply within a specific timeframe after purchasing. In some states (like Florida and Texas), homestead exemptions also provide additional legal protections against creditors and forced sale. Check with your county tax assessor.", cat: "after" },
  { q: "How do I change the name on my deed?", a: "To add or remove someone from your deed (after marriage, divorce, inheritance, or estate planning), you'll need a new deed prepared and recorded with the county. This typically requires: a real estate attorney to prepare the deed, notarization of signatures, recording with the county recorder, and notification to your lender (important — some loans have a 'due on sale' clause). Title insurance for the new deed is recommended. Don't attempt this without legal guidance.", cat: "after" },
  { q: "What is a home equity line of credit (HELOC)?", a: "A HELOC is a revolving line of credit secured by your home equity. It works like a credit card — you can borrow up to your credit limit, repay, and borrow again during the 'draw period' (typically 10 years). After that, the 'repayment period' begins (typically 20 years). HELOCs usually have variable interest rates. Most lenders require at least 15-20% equity. A new title search is required to verify no additional liens exist. Use responsibly — your home is the collateral.", cat: "after" },

  // === MORE FRAUD ===
  { q: "What is seller impersonation fraud?", a: "A growing scam where criminals impersonate property owners — often targeting vacant land, rental properties, or out-of-state owners. They create fake IDs, forge deeds, and attempt to sell property they don't own. Title searches and title insurance protect against this, but the scam can still cause delays and legal headaches. Red flags: seller unwilling to meet in person, wants to close unusually fast, provides wire instructions for funds to go overseas. Source: FBI", cat: "fraud" },
  { q: "What is a Business Email Compromise (BEC) attack?", a: "BEC is the primary vehicle for real estate wire fraud. Hackers gain access to a real email account (agent, lender, or title company) and monitor the conversation, waiting for closing to approach. They then send an email — from the real account or a convincing lookalike — with fraudulent wire instructions. BEC accounted for $2.77 billion in losses across all industries in 2024. In real estate, it's the most common attack vector. Multi-factor authentication is the #1 defense. Source: FBI IC3", cat: "fraud" },

  // === MORE TITLE INSURANCE ===
  { q: "Do I need title insurance if I'm paying cash?", a: "There's no lender requiring it, but owner's title insurance is even MORE important for cash buyers. Without a mortgage lender providing an extra layer of review, you're solely responsible for ensuring the title is clear. A title search and owner's policy protect your entire investment — which is 100% of the purchase price when paying cash. The one-time cost (0.5-1% of price) is negligible compared to the risk of an uninsured title claim.", cat: "insurance" },
  { q: "Does title insurance cover boundary disputes?", a: "The standard ALTA Owner's Policy covers certain boundary issues — specifically, if someone else has an easement or right to use your land, or if you lack legal access. For more comprehensive boundary protection, ask about a survey endorsement, which extends coverage to matters a survey would reveal (encroachments, boundary line discrepancies). Getting a survey before closing is recommended, especially for rural properties or when fences/structures are near property lines.", cat: "insurance" },
  { q: "What is title insurance for a condo?", a: "Condos have unique title considerations. Your owner's policy covers your individual unit, but common areas are typically covered under the HOA's master policy. Key condo-specific title issues: HOA liens (for unpaid dues), special assessments, right of first refusal provisions, and restrictions on use or rental. Ask about ALTA's condominium endorsement, which provides additional coverage specific to condo ownership. Review the HOA's financial health and reserve fund before purchasing.", cat: "insurance" },
  { q: "Is title insurance required by law?", a: "No state requires owner's title insurance by law — it's optional but strongly recommended. However, almost all mortgage lenders require a lender's title insurance policy as a condition of the loan. The lender's policy only protects the bank — not you. That's why purchasing a separate owner's policy is so important. It's the only protection you have if someone challenges your ownership or a hidden lien surfaces after closing.", cat: "insurance" },

  // === MORE BASICS ===
  { q: "What is a survey and do I need one?", a: "A property survey determines the exact boundaries, dimensions, and location of structures on your land. It shows: property lines, easements, encroachments (structures crossing boundaries), setback violations, and flood zone status. Some lenders and title companies require a survey; others accept an existing one. A new survey costs $300-700. It's especially important for: rural properties, properties with fences or outbuildings near boundaries, waterfront properties, and any property where boundaries are unclear.", cat: "basics" },
  { q: "What is a quitclaim deed?", a: "A quitclaim deed transfers whatever ownership interest the grantor may have — without making any guarantees about the quality of that title. It provides NO warranty that the grantor actually owns the property or that the title is clear. Quitclaim deeds are commonly used between family members, to add/remove a spouse after marriage/divorce, or to correct a name on a deed. They should NEVER be used for a standard purchase — always insist on a warranty deed for purchases.", cat: "basics" },
  { q: "What is a short sale?", a: "A short sale occurs when a homeowner sells their property for less than the outstanding mortgage balance, with the lender's approval. The lender agrees to accept less than what's owed to avoid the cost and time of foreclosure. Short sales take longer to close (3-6 months or more) because the lender must approve the sale price. Title insurance is especially important in short sales — there may be additional liens, judgments, or complications. Source: NAR", cat: "basics" },
  { q: "What is foreclosure and how does it affect title?", a: "Foreclosure is the legal process by which a lender takes possession of a property when the borrower defaults on the mortgage. Foreclosure can create title complications: junior liens may or may not be extinguished, there may be redemption periods allowing the former owner to reclaim the property, and IRS tax liens have special rules. Title insurance is critical when buying a foreclosure — it protects against these complex title issues that are common in distressed properties.", cat: "basics" },
];
